VALUES
  ('social-worker-moex-02361', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '專家學者在相關研究中發現穩定的有氧運動對人體是有幫助，同時現代人認為運動很重要，也表示願意 多運動，且我們看到有很多人會運用腳踏車或走路來替代其他交通工具代步。請問何者為表達性需求？', '["「專家學者在相關研究中發現穩定的有氧運動對人體是有幫助」是表達性需求", "「現代人認為運動很重要」是表達性需求", "「很多人會運用腳踏車或走路來替代其他交通工具代步」是表達性需求", "「很多人表達願意多運動」是表達性需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02362', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '分析過去服務統計量，並且盤點現有服務資源，推估可能有更多服務需求的區域或項目是下列那一種需 求？', '["規範性需求", "相對性需求", "感受性需求", "表達性需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02363', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '針對夜市從事攤販工作的家庭，提供兒少夜間照顧到凌晨，再與父母一起下班。請問下列何者可能為最 適合本方案的因果假設？', '["若可以不要讓兒少在夜市出現，將有助於提升案主的自尊心", "若可以提供補救教學服務，將可能提升社會階層翻轉的機會", "若可以讓兒少在夜間接受妥善且安全的照顧，則將有助於兒少穩定及安全的身心發展", "若可以幫助照顧兒童，父母所得將可能增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02364', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案評估需要設定成效指標，以未成年懷孕少女親職教育服務方案為例，下列何者最符合「成效指標」 設定方式？', '["60%接受方案服務的懷孕少女可以辨識出五種以上的營養食品", "生下健康嬰兒", "80%成員全程參加活動", "100%參與成員都表示很滿意活動場地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02365', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '倘若學生可以接受到老師「多元教學媒材」且「小組討論」等激勵思考的教學技術，則可加強課程內容 的深度思辨，並提升未來實務工作上運用的可能性。請問下列方案目標元素敘述正確的是：', '["老師－服務對象", "接受多元教學媒材且小組討論等激勵教學技術－改變標的", "學生提升課程內容的深度思辨能力－方案的影響", "提升未來實務工作上運用的可能性－方案策略"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02366', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案評估方式有內部評估及外部評估，試問以下那個是「內部」評估的優勢？', '["維持評估工作的客觀性", "缺乏獨立自主的可靠性", "較易獲得主事者和員工的信任", "提高可信度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02367', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作督導的焦點與功能中，下列敘述何者錯誤？', '["探究與表達個人工作困擾，提供再刺激的空間－支持性功能", "確保工作的品質，並規劃適合每個人的工作內容－行政性功能", "提供員工在工作內發展理解力與技能，並提供工作相關訊息及觀點－教育性功能", "確保做為一個「人」和「工作者」，不會讓他獨自去承擔不必要的困難、問題和設計－調解性功能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02368', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Kirkpatrick（柯克柏翠）針對教育訓練分為四層次評估，請問一般機構常用「滿意度調查問卷」，屬於那 一類？', '["學習層次（Learning level）", "反應層次（Reaction level）", "行為層次（Behavior level）", "結果層次（Result level）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02369', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作督導中有所謂同儕督導，下列何者對同儕督導敘述，最為適切？', '["同儕間彼此經驗分享，針對領導階層及機構進行評估", "同儕間猶如成長團體，大家可以自由進出，無學習成效評估", "透過同儕經驗分享，產生鷹架學習效果，讓服務效能提升", "邀請不同領域的專家，來針對同儕需要，提供新的刺激"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02370', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作服務機構在提供服務時，強調容易取得，包含：時間、地方、方式的便利性，是那種品質指標？', '["信賴性", "公平性", "可近性", "持續性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "dfdd0f76d597", "answer_pdf_sha1": "00ca17cc65d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
